import { Paper, ScrollArea, Table, TableTbody, TableTd, TableTh, TableThead, TableTr, VisuallyHidden } from '@mantine/core';
import { type TableName, TableNameSchema } from 'prisma/zod/schemas';
import { useMemo } from 'react';

import { PlayerLink } from '@/components/PlayerLink/PlayerLink';
import { TableScore } from '@/components/TableScore/TableScore';
import { PlayerRecordDataType } from '@/types';

export interface Props {
    table: TableName;
    year: number;
    records: PlayerRecordDataType[];
}

const rankFieldByTable = {
    [TableNameSchema.enum.points]: 'rankPoints',
    [TableNameSchema.enum.averages]: 'rankAverages',
    [TableNameSchema.enum.stalwart]: 'rankStalwart',
    [TableNameSchema.enum.speedy]: 'rankSpeedy',
    [TableNameSchema.enum.pub]: 'rankPub',
} satisfies Record<TableName, keyof PlayerRecordDataType>;

type RankField = (typeof rankFieldByTable)[TableName];

const scoreHeadingByTable = {
    [TableNameSchema.enum.points]: 'Points',
    [TableNameSchema.enum.averages]: 'Average',
    [TableNameSchema.enum.stalwart]: 'Games Played',
    [TableNameSchema.enum.speedy]: 'Average Response Time (hh:mm:ss)',
    [TableNameSchema.enum.pub]: 'Pub Score',
} satisfies Record<TableName, string>;

interface RankDisplay {
    text: string;
    visible: boolean;
}

const rankDisplays = (records: PlayerRecordDataType[], rankField: RankField): RankDisplay[] => {
    const displays: RankDisplay[] = [];
    let prevRank: number | null | undefined;

    for (const record of records) {
        const rank = record[rankField];
        const isMissing = rank === null || rank === undefined;

        displays.push({
            text: isMissing ? '-' : `${rank}`,
            visible: isMissing || rank !== prevRank,
        });

        prevRank = rank;
    }

    return displays;
};

export const RecordsTable = ({ table, year, records }: Props) => {
    const rankField = rankFieldByTable[table];
    const scoreHeading = scoreHeadingByTable[table];
    const ranks = useMemo(() => rankDisplays(records, rankField), [records, rankField]);

    return (
        <Paper p="sm" miw="14rem" maw="24rem" h="100%" withBorder>
            <ScrollArea type="auto" role="region">
                <Table>
                    <TableThead>
                        <TableTr>
                            <TableTh>Position</TableTh>
                            <TableTh>Player</TableTh>
                            <TableTh>{scoreHeading}</TableTh>
                        </TableTr>
                    </TableThead>
                    <TableTbody>
                        {records.map((record, index) => (
                            <TableTr
                                key={record.id}
                                bd={ranks[index + 1]?.visible === false ? '0' : undefined}
                            >
                                <TableTd>
                                    {ranks[index].visible ?
                                        ranks[index].text :
                                        <VisuallyHidden>{ranks[index].text}</VisuallyHidden>}
                                </TableTd>
                                <TableTd>
                                    <PlayerLink player={record.player} year={year} />
                                </TableTd>
                                <TableTd>
                                    <TableScore table={table} playerRecord={record} />
                                </TableTd>
                            </TableTr>
                        ))}
                    </TableTbody>
                </Table>
            </ScrollArea>
        </Paper>
    );
};

import { Group, Stack } from '@mantine/core';
import { Metadata } from 'next';
import { notFound, permanentRedirect } from 'next/navigation';
import { TableNameSchema } from 'prisma/zod/schemas';
import { cache } from 'react';
import z from 'zod';

import { AutoRefresh } from '@/components/AutoRefresh/AutoRefresh';
import { TitleWithYearDropdown } from '@/components/TitleWithYearDropdown/TitleWithYearDropdown';
import { YearTable } from '@/components/YearTable/YearTable';
import { QualifiedTableName, TableTitle } from '@/lib/tables';
import playerRecordService from '@/services/PlayerRecord';
import { FootyChannel } from '@/types/FootyChannel';

interface PageProps {
    params: Promise<{
        table: string,
    }>,
    searchParams?: Promise<{
        year?: string;
    }>;
}

/**
 * Unpacks and validates page parameters and search parameters for the footy
 * table page.
 *
 * This function validates the table name parameter against the TableNameSchema,
 * validates the year search parameter, and ensures the year exists in the
 * available years. It also handles canonical URL redirects to ensure consistent
 * URL formatting.
 *
 * @param params - The page route parameters containing the table name
 * @param searchParams - The URL search parameters, optionally containing a year
 * @returns A promise resolving to an object containing the validated table
 * name, year, and all available years
 * @throws {notFound} When the table parameter is invalid, year is invalid, or
 * year is not in the available years list
 * @throws {permanentRedirect} When the current URL doesn't match the canonical
 * URL format
 *
 * @example
 * ```tsx
 * const { table, year, allYears } = await unpackParams(params, searchParams);
 * ```
 */
const unpackParams = cache(async (
    params: PageProps['params'],
    searchParams: PageProps['searchParams'],
) => {
    const { table: tableParam } = await params;

    const tableResult = TableNameSchema.safeParse(tableParam);
    if (!tableResult.success) notFound();
    const table = tableResult.data;

    const resolvedSearchParams = await searchParams;
    const allYears = await playerRecordService.getAllYears({
        completed: false,
        mostRecentFirst: true,
    });
    const yearResult = z.coerce.number().int().min(0).safeParse(resolvedSearchParams?.year ?? 0);
    const year = yearResult.success ? yearResult.data : undefined;
    if (year === undefined || !allYears.includes(year)) notFound();

    const canonicalSearch = year ? `?year=${year}` : '';
    const canonicalUrl = `/footy/table/${table}${canonicalSearch}`;
    const currentSearch = resolvedSearchParams?.year ? `?year=${resolvedSearchParams.year}` : '';
    const currentUrl = `/footy/table/${table}${currentSearch}`;
    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);

    return { table, year, allYears };
});

/**
 * Generates metadata for the table page.
 * @param props - The page properties containing params and searchParams
 * @param props.params - The route parameters
 * @param props.searchParams - The search query parameters
 * @returns A promise that resolves to the page metadata with the qualified
 * table name as title
 */
export async function generateMetadata(props: PageProps): Promise<Metadata> {
    const { table, year } = await unpackParams(props.params, props.searchParams);

    return {
        title: QualifiedTableName(table, year),
    };
}

/**
 * Renders the Footy table page for a specific table and year.
 *
 * This async server component:
 * - Resolves route and query parameters via `unpackParams`.
 * - Fetches both qualified and unqualified player records for the selected
 *   table/year.
 * - Displays a `TitleWithYearDropdown` and a `YearTable` populated with the
 *   retrieved data.
 *
 * @param props - Next.js page props containing dynamic route params and search
 * params.
 * @returns A React element with year selection controls and table results.
 */
const TablePage = async (props: PageProps) => {
    const { table, year, allYears } = await unpackParams(props.params, props.searchParams);

    const [tableQualified, tableUnqualified] = await Promise.all([
        playerRecordService.getTable(table, year, true),
        playerRecordService.getTable(table, year, false),
    ]);

    return (
        <>
            <AutoRefresh channels={[FootyChannel.Results, FootyChannel.Players]} />
            <Stack w="100%" h="70vh" p="xl" align="center" style={{ overflow: 'auto' }}>
                <Group justify="center" w="100%">
                    <TitleWithYearDropdown order={1} title={`${TableTitle(table)}: `} year={year} validYears={allYears} />
                </Group>
                <YearTable
                    table={table}
                    year={year}
                    qualified={tableQualified}
                    unqualified={tableUnqualified}
                />
            </Stack>
        </>
    );
};

export default TablePage;

