import { Box, Collapse, Flex, Group, rem, UnstyledButton } from '@mantine/core';
import { IconChevronRight } from '@tabler/icons-react';
import Link from 'next/link';
import { useState } from 'react';

import classes from '@/components/NavBarLinksGroup/NavBarLinksGroup.module.css';

interface NavBarLinksGroupProps {
    label: string;
    initiallyOpened?: boolean;
    links?: { label: string; link: string }[];
}

export const NavBarLinksGroup = ({
    label,
    initiallyOpened,
    links,
}: NavBarLinksGroupProps) => {
    const hasLinks = Array.isArray(links);
    const [opened, setOpened] = useState(initiallyOpened ?? false);
    const items = (hasLinks ? links : []).map((link) => (
        <Link className={classes.link} href={link.link} key={link.label}>
            {link.label}
        </Link>
    ));
    const icon = hasLinks ? (
        <IconChevronRight
            className={classes.chevron}
            stroke={1.5}
            style={{
                width: rem(16),
                height: rem(16),
                transform: opened ? 'rotate(-90deg)' : 'none',
            }}
        />
    ) : null;

    return (
        <>
            <UnstyledButton onClick={() => setOpened((o) => !o)} className={classes.control}>
                <Group justify="space-between" gap={0}>
                    <Flex align="center">
                        <Box ml="md">{label}</Box>
                    </Flex>
                    {icon}
                </Group>
            </UnstyledButton>
            {hasLinks ? <Collapse expanded={opened}>{items}</Collapse> : null}
        </>
    );
};

