        it('reveals the remaining rows when the toggle is clicked, then hides them again', async () => {
            const user = userEvent.setup();
            render(
                <Wrapper>
                    <RecordsTable
                        table={TableNameSchema.enum.points}
                        year={2024}
                        records={untiedRecords}
                    />
                </Wrapper>,
            );

