        });
    });

    describe('title', () => {
        it('renders no heading or divider when no title is given', () => {
            render(
                <Wrapper>
                    <RecordsTable
                        table={TableNameSchema.enum.points}
                        year={2024}
                        records={[createMockPlayerRecordData()]}
                    />
                </Wrapper>,
